import os
import re
import json
import boto3
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.service import Service
from selenium.webdriver.chrome.options import Options
from urllib.parse import urlparse

app = Flask(__name__)

# AWS S3 Configuration
s3_client = boto3.client('s3')
BUCKET_NAME = 'your-s3-bucket-name'

# Allowlist of domains
ALLOWLIST = ['example.com', 'another-example.com']

# Function to validate URL
def is_valid_url(url):
    parsed_url = urlparse(url)
    if parsed_url.scheme not in ['http', 'https']:
        return False
    if parsed_url.netloc not in ALLOWLIST:
        return False
    return True

# Function to take a screenshot
def take_screenshot(url):
    chrome_options = Options()
    chrome_options.add_argument("--headless")
    chrome_options.add_argument("--no-sandbox")
    chrome_options.add_argument("--disable-dev-shm-usage")
    
    service = Service('/path/to/chromedriver')
    driver = webdriver.Chrome(service=service, options=chrome_options)
    driver.get(url)
    screenshot_path = '/tmp/screenshot.png'
    driver.save_screenshot(screenshot_path)
    driver.quit()
    return screenshot_path

# Function to upload to S3
def upload_to_s3(file_path, s3_key):
    s3_client.upload_file(file_path, BUCKET_NAME, s3_key)

@app.route('/screenshot', methods=['POST'])
def screenshot_service():
    data = request.json
    url = data.get('url')

    if not is_valid_url(url):
        return jsonify({'error': 'Invalid URL'}), 400

    screenshot_path = take_screenshot(url)
    s3_key = f'screenshots/{os.path.basename(urlparse(url).path)}.png'
    upload_to_s3(screenshot_path, s3_key)

    return jsonify({'s3_url': f'https://{BUCKET_NAME}.s3.amazonaws.com/{s3_key}'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=int(os.environ.get('PORT', 5000)))